package com.example.oauthclient;

import java.io.IOException;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.util.LinkedHashMap;
import java.util.Map;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;

import jakarta.servlet.http.HttpServletResponse;

@SpringBootApplication
public class OAuthClientApplication {
    public static void main(String[] args) {
        SpringApplication.run(OAuthClientApplication.class, args);
    }
}

@Controller
class OAuthController {

    @Value("${oauth2.authorization-uri}")
    private String authorizationUri;

    @Value("${oauth2.client-id}")
    private String clientId;

    @Value("${oauth2.redirect-uri}")
    private String redirectUri;

    @Value("${oauth2.scope}")
    private String scope;

    @GetMapping("/login")
    public void login(HttpServletResponse response) throws IOException {
        String authUrl = buildAuthorizationUrl();
        response.sendRedirect(authUrl);
    }

    @GetMapping("/callback")
    public String callback(@RequestParam(required = false) String code,
                           @RequestParam(required = false) String error,
                           @RequestParam(required = false) String error_description) {
        if (error != null) {
            return "OAuth error: " + error + (error_description != null ? " - " + error_description : "");
        }
        return "Authorization code received: " + code;
    }

    private String buildAuthorizationUrl() {
        Map<String, String> params = new LinkedHashMap<>();
        params.put("client_id", clientId);
        params.put("redirect_uri", redirectUri);
        params.put("scope", scope);
        params.put("response_type", "code");

        StringBuilder url = new StringBuilder(authorizationUri);
        if (!authorizationUri.contains("?")) {
            url.append("?");
        } else if (!authorizationUri.endsWith("&") && !authorizationUri.endsWith("?")) {
            url.append("&");
        }

        boolean first = true;
        for (Map.Entry<String, String> entry : params.entrySet()) {
            if (!first) {
                url.append("&");
            }
            first = false;
            url.append(encode(entry.getKey()))
               .append("=")
               .append(encode(entry.getValue()));
        }
        return url.toString();
    }

    private String encode(String value) {
        return URLEncoder.encode(value, StandardCharsets.UTF_8);
    }
}